import React, { useEffect, useState } from 'react';
import axios from 'axios';

const Home = () => {
    const [songs, setSongs] = useState([]);
    const [currentSong, setCurrentSong] = useState(null);

    useEffect(() => {
        const fetchSongs = async () => {
            try {
                const res = await axios.get('http://localhost:5000/api/songs');
                setSongs(res.data);
            } catch (err) { console.error(err); }
        };
        fetchSongs();
    }, []);

    return (
        <div style={{ padding: '20px', maxWidth: '900px', margin: '0 auto', fontFamily: 'Arial' }}>
            <h2 style={{ textAlign: 'center', marginBottom: '30px' }}>DANH SÁCH BÀI HÁT</h2>
            
            <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                {songs.map((song) => (
                    <div key={song._id} style={{
                        display: 'flex', 
                        flexDirection: 'row', // Đảm bảo nằm hàng ngang
                        alignItems: 'center', 
                        padding: '12px 20px', 
                        border: '1px solid #eee', 
                        borderRadius: '12px',
                        background: currentSong?._id === song._id ? '#f0f7ff' : '#fff',
                        boxShadow: '0 2px 5px rgba(0,0,0,0.05)',
                        justifyContent: 'space-between' // Đẩy nút Play sang phải
                    }}>
                        <div style={{ display: 'flex', alignItems: 'center' }}>
                            <img 
                                src={song.imageUrl ? `http://localhost:5000${song.imageUrl}` : 'https://via.placeholder.com/60'} 
                                alt="cover" 
                                style={{ width: '60px', height: '60px', borderRadius: '8px', marginRight: '20px', objectFit: 'cover' }}
                            />
                            <div style={{ textAlign: 'left' }}>
                                <div style={{ fontWeight: 'bold', fontSize: '18px' }}>{song.title}</div>
                                <div style={{ fontSize: '14px', color: '#666' }}>{song.artist}</div>
                            </div>
                        </div>

                        <button 
                            onClick={() => setCurrentSong(song)}
                            style={{ 
                                padding: '10px 25px', 
                                cursor: 'pointer', 
                                background: '#28a745', 
                                color: '#fff', 
                                border: 'none', 
                                borderRadius: '25px',
                                fontWeight: 'bold',
                                width: 'auto' // Quan trọng: Để nút không bị to hết cỡ
                            }}
                        >
                            PLAY
                        </button>
                    </div>
                ))}
            </div>

            {currentSong && (
                <div style={{
                    position: 'fixed', bottom: 0, left: 0, right: 0, 
                    background: '#1a1a1a', color: '#fff', padding: '15px 20px', 
                    display: 'flex', flexDirection: 'column', alignItems: 'center', zIndex: 1000,
                    boxShadow: '0 -5px 20px rgba(0,0,0,0.5)'
                }}>
                    {/* Thông tin bài hát đang phát */}
                    <div style={{ marginBottom: '10px', fontSize: '14px' }}>
                        Đang phát: <span style={{ color: '#28a745', fontWeight: 'bold' }}>{currentSong.title}</span> - {currentSong.artist}
                    </div>

                    {/* Bộ nút điều khiển: Lùi - Play/Pause - Tiến */}
                    <div style={{ display: 'flex', alignItems: 'center', gap: '30px', marginBottom: '10px' }}>
                        <button onClick={handlePrev} style={controlBtnStyle}>⏮</button>
                        
                        {/* Nút Play trung tâm (Sử dụng icon hoặc text) */}
                        <div style={{ 
                            width: '50px', height: '50px', background: '#28a745', 
                            borderRadius: '50%', display: 'flex', alignItems: 'center', 
                            justifyContent: 'center', cursor: 'pointer', fontSize: '24px' 
                        }}>
                            ▶
                        </div>

                        <button onClick={handleNext} style={controlBtnStyle}>⏭</button>
                    </div>

                    {/* Thanh Audio mặc định */}
                    <audio 
                        ref={audioRef}
                        src={`http://localhost:5000${currentSong.songUrl}`} 
                        controls 
                        autoPlay 
                        onEnded={handleNext} // Tự động chuyển bài khi kết thúc
                        style={{ width: '100%', maxWidth: '700px', height: '35px' }} 
                    />
                </div>
            )}
        </div>
    );
};

// Style cho các nút điều khiển lùi/tiến
const controlBtnStyle = {
    background: 'none',
    border: 'none',
    color: '#fff',
    fontSize: '30px',
    cursor: 'pointer',
    transition: 'color 0.2s',
    outline: 'none'
};

export default Home;
